	title: string | null
	summary: string | null
	documentType: string
	createdAt: string
	updatedAt: string
	x: number
	y: number
	memories: GraphApiMemory[]
}

export interface GraphApiEdge {
	source: string
	target: string
	similarity: number
}

export interface GraphViewportResponse {
	documents: GraphApiDocument[]
	edges: GraphApiEdge[]
	viewport: { minX: number; maxX: number; minY: number; maxY: number }
	totalCount: number
}

export interface GraphBoundsResponse {
	bounds: {
		minX: number
		maxX: number
		minY: number
		maxY: number
	} | null
}

export function getMemoryText(m: Memory): string {
	return "memory" in m ? m.memory : m.chunk
}

function limitByChars(text: string, maxChars = MAX_CHARS): string {
	return text.length > maxChars ? `${text.slice(0, maxChars)}...` : text
}

// Type for SDK search result item
interface SDKResult {
	id: string
	memory?: string
	chunk?: string
	content?: string
	similarity: number
	title?: string
	context?: string
}

export class SupermemoryClient {
	private client: Supermemory
	private containerTag: string
	private bearerToken: string
	private apiUrl: string

	constructor(
		bearerToken: string,
		containerTag?: string,
		apiUrl = "https://api.supermemory.ai",
	) {
		this.bearerToken = bearerToken
		this.apiUrl = apiUrl
		this.client = new Supermemory({
			apiKey: bearerToken,
			baseURL: apiUrl,
		})
		this.containerTag = containerTag || DEFAULT_PROJECT_ID
	}

	// Create memory using SDK
	async createMemory(
		content: string,
	): Promise<{ id: string; status: string; containerTag: string }> {
		try {
			const result = await this.client.add({
				content,
				containerTag: this.containerTag,
				metadata: {
					sm_source: "mcp",
				},
			})
			return {
				id: result.id,
				status: "queued",
				containerTag: this.containerTag,
			}
		} catch (error) {
			this.handleError(error)
		}
	}

	// Delete/forget memory - try exact match first, then semantic search
	async forgetMemory(
		content: string,
	): Promise<{ success: boolean; message: string; containerTag: string }> {
		try {
			// Try exact content matching first
			try {
				const result = await this.client.memories.forget({
					content: content,
					containerTag: this.containerTag,
				})

				return {
					success: true,
					message: `Successfully forgot memory (exact match) with ID: ${result.id}`,
					containerTag: this.containerTag,
				}
			} catch (error: any) {
				// If not 404, it's a real error - re-throw it
				if (error?.status !== 404) {
					throw error
				}
				// Otherwise continue to semantic search fallback
			}

			// Fallback to semantic search if exact match fails
			const SIMILARITY_THRESHOLD = 0.85 // High threshold - only very similar memories
			const searchResult = await this.search(content, 5, SIMILARITY_THRESHOLD)

			if (searchResult.results.length === 0) {
				return {
					success: false,
					message: `No matching memory found to forget. Tried exact match and semantic search with similarity threshold ${SIMILARITY_THRESHOLD}.`,
					containerTag: this.containerTag,
				}
			}

			// Only actual memories (not chunks) can be forgotten
			const memoryToDelete = searchResult.results.find((r) => "memory" in r)
			if (!memoryToDelete) {
				return {
					success: false,
					message:
						"No matching memory found to forget (only document chunks matched in semantic search).",
					containerTag: this.containerTag,
				}
			}

			// Delete using the ID from semantic search
			await this.client.memories.forget({
				id: memoryToDelete.id,
				containerTag: this.containerTag,
			})

			const memoryText =
				getMemoryText(memoryToDelete) || memoryToDelete.content || ""
			return {
				success: true,
				message: `Forgot similar memory (semantic match, similarity: ${memoryToDelete.similarity.toFixed(2)}): "${limitByChars(memoryText, 100)}"`,
				containerTag: this.containerTag,
			}
		} catch (error) {
			this.handleError(error)
		}
	}

	// Search memories using SDK
	async search(
		query: string,
		limit = 10,
		threshold?: number,
	): Promise<SearchResult> {
		try {
			const result = await this.client.search.memories({
				q: query,
				limit,
				containerTag: this.containerTag,
				searchMode: "hybrid",
				threshold, // Optional threshold parameter
			})

			// Normalize and limit response size — preserve memory vs chunk distinction
			const results: Memory[] = (result.results as SDKResult[]).map((r) => {
				const text = limitByChars(
					r.content || r.memory || r.chunk || r.context || "",
				)
				const base = {
					id: r.id,
					similarity: r.similarity,
					title: r.title,
					content: r.content,
				}
				if (r.chunk && !r.memory) {
					return { ...base, chunk: text }
				}
				return { ...base, memory: text }
			})

			return {
				results,
				total: result.total,
				timing: result.timing,
			}
		} catch (error) {
			this.handleError(error)
		}
	}

	// Get user profile using SDK
	async getProfile(query?: string): Promise<ProfileResponse> {
		try {
			const result = await this.client.profile({
				containerTag: this.containerTag,
				q: query,
			})

			const response: ProfileResponse = {
				profile: {
					static: result.profile?.static || [],
					dynamic: result.profile?.dynamic || [],
				},
			}

			if (result.searchResults) {
				response.searchResults = {
					results: (result.searchResults.results as SDKResult[]).map((r) => {
						const text = limitByChars(
							r.content || r.memory || r.chunk || r.context || "",
						)
						const base = {
							id: r.id,
							similarity: r.similarity,
							title: r.title,
							content: r.content,
						}
						if (r.chunk && !r.memory) {
							return { ...base, chunk: text }
						}
						return { ...base, memory: text }
					}),
					total: result.searchResults.total,
					timing: result.searchResults.timing,
				}
			}

			return response
		} catch (error) {
			this.handleError(error)
		}
	}

	// Get projects list
	async getProjects(): Promise<string[]> {
		try {
			const response = await fetch(`${this.apiUrl}/v3/projects`, {
				method: "GET",
				headers: {
					Authorization: `Bearer ${this.bearerToken}`,
					"Content-Type": "application/json",
				},
			})

			if (!response.ok) {
				if (response.status === 401) {
					throw new Error("Authentication failed. Please re-authenticate.")
				}
				throw new Error(`Failed to fetch projects: ${response.statusText}`)
			}

			const data = (await response.json()) as {
				projects: Project[]
			}
			return data.projects?.map((p) => p.containerTag) || []
		} catch (error) {
			this.handleError(error)
		}
	}

	// Fetch graph bounds for coordinate range
	async getGraphBounds(containerTags?: string[]): Promise<GraphBoundsResponse> {
		try {
			const params = new URLSearchParams()
			if (containerTags?.length) {
				params.set("containerTags", JSON.stringify(containerTags))
			}
			const url = `${this.apiUrl}/v3/graph/bounds${params.toString() ? `?${params}` : ""}`
			const response = await fetch(url, {
				method: "GET",
				headers: {
					Authorization: `Bearer ${this.bearerToken}`,
					"Content-Type": "application/json",
				},
			})
			if (!response.ok) {
				throw Object.assign(new Error("Failed to fetch graph bounds"), {
					status: response.status,
				})
			}
			return (await response.json()) as GraphBoundsResponse
		} catch (error) {
			this.handleError(error)
		}
	}

	// Fetch graph data for a viewport region
	async getGraphViewport(
		viewport: { minX: number; maxX: number; minY: number; maxY: number },
		containerTags?: string[],
		limit = 200,
	): Promise<GraphViewportResponse> {
		try {
			const response = await fetch(`${this.apiUrl}/v3/graph/viewport`, {
				method: "POST",
				headers: {
					Authorization: `Bearer ${this.bearerToken}`,
					"Content-Type": "application/json",
				},
				body: JSON.stringify({ viewport, containerTags, limit }),
			})
			if (!response.ok) {
				throw Object.assign(new Error("Failed to fetch graph viewport"), {
					status: response.status,
				})
			}
			return (await response.json()) as GraphViewportResponse
		} catch (error) {
			this.handleError(error)
		}
	}

	private handleError(error: unknown): never {
		// Handle network/fetch errors
		if (error instanceof TypeError) {
			if (
				error.message.includes("fetch") ||
				error.message.includes("network")
			) {
				throw new Error(
					"Network error. Please check your connection and try again.",
				)
			}
		}

		// Handle HTTP status errors from SDK/fetch
		if (error && typeof error === "object" && "status" in error) {
			const status = (error as { status: number }).status
			const message =
				"message" in error ? (error as { message: string }).message : undefined

			switch (status) {
				case 400:
				case 422:
					throw new Error(
						message || "Invalid request parameters. Please check your input.",
					)
				case 401:
					throw new Error("Authentication failed. Please re-authenticate.")
				case 402:
					throw new Error("Memory limit reached. Upgrade at supermemory.ai")
				case 403:
					throw new Error(
						"Access forbidden. Your account may be restricted or blocked.",
					)
				case 404:
					throw new Error("Memory not found. It may have been deleted.")
				case 429:
					throw new Error(
						"Rate limit exceeded. Please wait a moment and try again.",
					)
				default:
					if (status >= 500) {
						throw new Error(
							"Server error. The service may be temporarily unavailable. Please try again later.",
						)
					}
			}
		}

		// Re-throw Error instances as-is
		if (error instanceof Error) {
			throw error
		}

		// Wrap unknown errors
		throw new Error(`An unexpected error occurred: ${String(error)}`)
	}
}

import type OpenAI from "openai"
import Supermemory from "supermemory"
import { addConversation } from "../conversations-client"
import { deduplicateMemories } from "../tools-shared"
import { createLogger, type Logger } from "../vercel/logger"
import { convertProfileToMarkdown } from "../vercel/util"

const normalizeBaseUrl = (url?: string): string => {
	const defaultUrl = "https://api.supermemory.ai"
	if (!url) return defaultUrl
	return url.endsWith("/") ? url.slice(0, -1) : url
}

export interface OpenAIMiddlewareOptions {
	conversationId?: string
	verbose?: boolean
	mode?: "profile" | "query" | "full"
	addMemory?: "always" | "never"
	baseUrl?: string
}

interface SupermemoryProfileSearch {
	profile: {
		static?: Array<{ memory: string; metadata?: Record<string, unknown> }>
		dynamic?: Array<{ memory: string; metadata?: Record<string, unknown> }>
	}
	searchResults: {
		results: Array<{ memory: string; metadata?: Record<string, unknown> }>
	}
}

/**
 * Extracts the last user message from an array of chat completion messages.
 *
 * Searches through the messages array in reverse order to find the most recent
 * message with role "user" and returns its content as a string.
 *
 * @param messages - Array of chat completion message parameters
 * @returns The content of the last user message, or empty string if none found
 *
 * @example
 * ```typescript
 * const messages = [
 *   { role: "system", content: "You are a helpful assistant." },
 *   { role: "user", content: "Hello there!" },
 *   { role: "assistant", content: "Hi! How can I help you?" },
 *   { role: "user", content: "What's the weather like?" }
 * ]
 *
 * const lastMessage = getLastUserMessage(messages)
 * // Returns: "What's the weather like?"
 * ```
 */
const getLastUserMessage = (
	messages: OpenAI.Chat.Completions.ChatCompletionMessageParam[],
) => {
	const lastUserMessage = messages
		.slice()
		.reverse()
		.find((msg) => msg.role === "user")

	return typeof lastUserMessage?.content === "string"
		? lastUserMessage.content
		: ""
}

/**
 * Searches for memories using the SuperMemory profile API.
 *
 * Makes a POST request to the SuperMemory API to retrieve user profile memories
 * and search results based on the provided container tag and optional query text.
 *
 * @param containerTag - The container tag/identifier for memory search (e.g., user ID, project ID)
 * @param queryText - Optional query text to search for specific memories. If empty, returns all profile memories
 * @returns Promise that resolves to the SuperMemory profile search response
 * @throws {Error} When the API request fails or returns an error status
 *
 * @example
 * ```typescript
 * // Search with query
 * const results = await supermemoryProfileSearch("user-123", "favorite programming language")
 *
 * // Get all profile memories
 * const profile = await supermemoryProfileSearch("user-123", "")
 * ```
 */
const supermemoryProfileSearch = async (
	containerTag: string,
	queryText: string,
	baseUrl: string,
): Promise<SupermemoryProfileSearch> => {
	const payload = queryText
		? JSON.stringify({
				q: queryText,
				containerTag: containerTag,
			})
		: JSON.stringify({
				containerTag: containerTag,
			})

	try {
		const response = await fetch(`${baseUrl}/v4/profile`, {
			method: "POST",
			headers: {
				"Content-Type": "application/json",
				Authorization: `Bearer ${process.env.SUPERMEMORY_API_KEY}`,
			},
			body: payload,
		})

		if (!response.ok) {
			const errorText = await response.text().catch(() => "Unknown error")
			throw new Error(
				`Supermemory profile search failed: ${response.status} ${response.statusText}. ${errorText}`,
			)
		}

		return await response.json()
	} catch (error) {
		if (error instanceof Error) {
			throw error
		}
		throw new Error(`Supermemory API request failed: ${error}`)
	}
}

/**
 * Adds memory-enhanced system prompts to chat completion messages.
 *
 * Searches for relevant memories based on the specified mode and injects them
 * into the conversation. If a system prompt already exists, memories are appended
 * to it. Otherwise, a new system prompt is created with the memories.
 *
 * @param messages - Array of chat completion message parameters
 * @param containerTag - The container tag/identifier for memory search
 * @param logger - Logger instance for debugging and info output
 * @param mode - Memory search mode: "profile" (all memories), "query" (search-based), or "full" (both)
 * @returns Promise that resolves to enhanced messages with memory-injected system prompt
 *
 * @example
 * ```typescript
 * const messages = [
 *   { role: "user", content: "What's my favorite programming language?" }
 * ]
 *
 * const enhancedMessages = await addSystemPrompt(
 *   messages,
 *   "user-123",
 *   logger,
 *   "full"
 * )
 * // Returns messages with system prompt containing relevant memories
 * ```
 */
const addSystemPrompt = async (
	messages: OpenAI.Chat.Completions.ChatCompletionMessageParam[],
	containerTag: string,
	logger: Logger,
	mode: "profile" | "query" | "full",
	baseUrl: string,
) => {
	const systemPromptExists = messages.some((msg) => msg.role === "system")

	const queryText = mode !== "profile" ? getLastUserMessage(messages) : ""

	const memoriesResponse = await supermemoryProfileSearch(
		containerTag,
		queryText,
		baseUrl,
	)

	const memoryCountStatic = memoriesResponse.profile.static?.length || 0
	const memoryCountDynamic = memoriesResponse.profile.dynamic?.length || 0

	logger.info("Memory search completed for chat API", {
		containerTag,
		memoryCountStatic,
		memoryCountDynamic,
		queryText:
			queryText.substring(0, 100) + (queryText.length > 100 ? "..." : ""),
		mode,
	})

	const deduplicated = deduplicateMemories({
		static: memoriesResponse.profile.static,
		dynamic: memoriesResponse.profile.dynamic,
		searchResults: memoriesResponse.searchResults?.results,
	})

	logger.debug("Memory deduplication completed for chat API", {
		static: {
			original: memoryCountStatic,
			deduplicated: deduplicated.static.length,
		},
		dynamic: {
			original: memoryCountDynamic,
			deduplicated: deduplicated.dynamic.length,
		},
		searchResults: {
			original: memoriesResponse.searchResults?.results?.length,
			deduplicated: deduplicated.searchResults.length,
		},
	})

	const profileData =
		mode !== "query"
			? convertProfileToMarkdown({
					profile: {
						static: deduplicated.static,
						dynamic: deduplicated.dynamic,
					},
					searchResults: { results: [] },
				})
			: ""
	const searchResultsMemories =
		mode !== "profile"
			? `Search results for user's recent message: \n${deduplicated.searchResults
					.map((memory) => `- ${memory}`)
					.join("\n")}`
			: ""

	const memories = `${profileData}\n${searchResultsMemories}`.trim()

	if (memories) {
		logger.debug("Memory content preview for chat API", {
			content: memories,
			fullLength: memories.length,
		})
	}

	if (systemPromptExists) {
		logger.debug("Added memories to existing system prompt")
		return messages.map((msg) =>
			msg.role === "system"
				? { ...msg, content: `${msg.content} \n ${memories}` }
				: msg,
		)
	}

	logger.debug(
		"System prompt does not exist, created system prompt with memories",
	)
	return [{ role: "system" as const, content: memories }, ...messages]
}

/**
 * Converts an array of chat completion messages into a formatted conversation string.
 *
 * Transforms the messages array into a readable conversation format where each
 * message is prefixed with its role (User/Assistant) and messages are separated
 * by double newlines.
 *
 * @param messages - Array of chat completion message parameters
 * @returns Formatted conversation string with role prefixes
 *
 * @example
 * ```typescript
 * const messages = [
 *   { role: "user", content: "Hello!" },
 *   { role: "assistant", content: "Hi there!" },
 *   { role: "user", content: "How are you?" }
 * ]
 *
 * const conversation = getConversationContent(messages)
 * // Returns: "User: Hello!\n\nAssistant: Hi there!\n\nUser: How are you?"
 * ```
 */
const getConversationContent = (
	messages: OpenAI.Chat.Completions.ChatCompletionMessageParam[],
) => {
	return messages
		.map((msg) => {
			const role = msg.role === "user" ? "User" : "Assistant"
			const content = typeof msg.content === "string" ? msg.content : ""
			return `${role}: ${content}`
		})
		.join("\n\n")
}

/**
 * Adds a new memory to the SuperMemory system.
 *
 * Saves the provided content as a memory with the specified container tag and
 * optional custom ID. Logs success or failure information for debugging.
 *
 * If customId starts with "conversation:" and messages are provided, uses the
 * /v4/conversations endpoint with structured messages instead of the memories endpoint.
 *
 * @param client - SuperMemory client instance
 * @param containerTag - The container tag/identifier for the memory
 * @param content - The content to save as a memory (used for fallback)
 * @param customId - Optional custom ID for the memory (e.g., conversation:456)
 * @param logger - Logger instance for debugging and info output
 * @param messages - Optional OpenAI messages array (for conversation endpoint)
 * @param apiKey - API key for direct conversation endpoint calls
 * @param baseUrl - Base URL for API calls
 * @returns Promise that resolves when memory is saved (or fails silently)
 *
 * @example
 * ```typescript
 * await addMemoryTool(
 *   supermemoryClient,
 *   "user-123",
 *   "User: Hello\n\nAssistant: Hi!",
 *   "conversation:456",
 *   logger,
 *   messages, // OpenAI messages array
 *   apiKey,
 *   baseUrl
 * )
 * ```
 */
const addMemoryTool = async (
	client: Supermemory,
	containerTag: string,
	content: string,
	customId: string | undefined,
	logger: Logger,
	messages?: OpenAI.Chat.Completions.ChatCompletionMessageParam[],
	apiKey?: string,
	baseUrl?: string,
): Promise<void> => {
	try {
		if (customId && messages && apiKey) {
			const conversationId = customId.replace("conversation:", "")

			// Convert OpenAI messages to conversation format
			const conversationMessages = messages.map((msg) => ({
				role: msg.role as "user" | "assistant" | "system" | "tool",
				content:
					typeof msg.content === "string"
						? msg.content
						: Array.isArray(msg.content)
							? msg.content
									.filter((c) => c.type === "text")
									.map((c) => ({
										type: "text" as const,
										text: (c as { type: "text"; text: string }).text,
									}))
							: "",
				...((msg as any).name && { name: (msg as any).name }),
				...((msg as any).tool_calls && { tool_calls: (msg as any).tool_calls }),
				...((msg as any).tool_call_id && {
					tool_call_id: (msg as any).tool_call_id,
				}),
			}))

			const response = await addConversation({
				conversationId,
				messages: conversationMessages,
				containerTags: [containerTag],
				apiKey,
				baseUrl,
			})

			logger.info("Conversation saved successfully via /v4/conversations", {
				containerTag,
				conversationId,
				messageCount: messages.length,
				responseId: response.id,
			})
			return
		}

		// Fallback to old behavior for non-conversation memories
		const response = await client.add({
			content,
			containerTags: [containerTag],
			customId,
		})

		logger.info("Memory saved successfully", {
			containerTag,
			customId,
			contentLength: content.length,
			memoryId: response.id,
		})
	} catch (error) {
		logger.error("Error saving memory", {
			error: error instanceof Error ? error.message : "Unknown error",
		})
	}
}

/**
 * Creates SuperMemory middleware for OpenAI clients.
 *
 * This function creates middleware that automatically injects relevant memories
 * into OpenAI chat completions and optionally saves new memories. The middleware
 * can wrap existing OpenAI clients or create new ones with SuperMemory capabilities.
 *
 * @param containerTag - The container tag/identifier for memory search (e.g., user ID, project ID)
 * @param options - Optional configuration options for the middleware
 * @param options.conversationId - Optional conversation ID to group messages for contextual memory generation
 * @param options.verbose - Enable detailed logging of memory operations (default: false)
 * @param options.mode - Memory search mode: "profile" (all memories), "query" (search-based), or "full" (both) (default: "profile")
 * @param options.addMemory - Automatic memory storage mode: "always" or "never" (default: "never")
 * @returns Object with `wrapClient` and `createClient` methods
 * @throws {Error} When SUPERMEMORY_API_KEY environment variable is not set
 *
 * @example
 * ```typescript
 * const openaiWithSupermemory = createOpenAIMiddleware(openai, "user-123", {
 *   conversationId: "conversation-456",
 *   mode: "full",
 *   addMemory: "always",
 *   verbose: true
 * })
 *
 * ```
 */
export function createOpenAIMiddleware(
	openaiClient: OpenAI,
	containerTag: string,
	options?: OpenAIMiddlewareOptions,
) {
	const logger = createLogger(options?.verbose ?? false)
	const baseUrl = normalizeBaseUrl(options?.baseUrl)
	const client = new Supermemory({
		apiKey: process.env.SUPERMEMORY_API_KEY,
		...(baseUrl !== "https://api.supermemory.ai" ? { baseURL: baseUrl } : {}),
	})

	const conversationId = options?.conversationId
	const mode = options?.mode ?? "profile"
	const addMemory = options?.addMemory ?? "never"

	const originalCreate = openaiClient.chat.completions.create
	const originalResponsesCreate = openaiClient.responses?.create

	/**
	 * Searches for memories and formats them for injection into API calls.
	 *
	 * This shared function handles memory search and formatting for both Chat Completions
	 * and Responses APIs, reducing code duplication.
	 *
	 * @param queryText - The text to search for (empty string for profile-only mode)
	 * @param containerTag - The container tag for memory search
	 * @param logger - Logger instance
	 * @param mode - Memory search mode
	 * @param context - API context for logging differentiation
	 * @returns Formatted memories string
	 */
	const searchAndFormatMemories = async (
		queryText: string,
		containerTag: string,
		logger: Logger,
		mode: "profile" | "query" | "full",
		context: "chat" | "responses",
	) => {
		const memoriesResponse = await supermemoryProfileSearch(
			containerTag,
			queryText,
			baseUrl,
		)

		const memoryCountStatic = memoriesResponse.profile.static?.length || 0
		const memoryCountDynamic = memoriesResponse.profile.dynamic?.length || 0

		logger.info(`Memory search completed for ${context} API`, {
			containerTag,
			memoryCountStatic,
			memoryCountDynamic,
			queryText:
				queryText.substring(0, 100) + (queryText.length > 100 ? "..." : ""),
			mode,
		})

		const deduplicated = deduplicateMemories({
			static: memoriesResponse.profile.static,
			dynamic: memoriesResponse.profile.dynamic,
			searchResults: memoriesResponse.searchResults?.results,
		})

		logger.debug(`Memory deduplication completed for ${context} API`, {
			static: {
				original: memoryCountStatic,
				deduplicated: deduplicated.static.length,
			},
			dynamic: {
				original: memoryCountDynamic,
				deduplicated: deduplicated.dynamic.length,
			},
			searchResults: {
				original: memoriesResponse.searchResults?.results?.length,
				deduplicated: deduplicated.searchResults.length,
			},
		})

		const profileData =
			mode !== "query"
				? convertProfileToMarkdown({
						profile: {
							static: deduplicated.static,
							dynamic: deduplicated.dynamic,
						},
						searchResults: { results: [] },
					})
				: ""
		const searchResultsMemories =
			mode !== "profile"
				? `Search results for user's ${context === "chat" ? "recent message" : "input"}: \n${deduplicated.searchResults
						.map((memory) => `- ${memory}`)
						.join("\n")}`
				: ""

		const memories = `${profileData}\n${searchResultsMemories}`.trim()

		if (memories) {
			logger.debug(`Memory content preview for ${context} API`, {
				content: memories,
				fullLength: memories.length,
			})
		}

		return memories
	}

	const createResponsesWithMemory = async (
		params: Parameters<typeof originalResponsesCreate>[0],
	) => {
		if (!originalResponsesCreate) {
			throw new Error(
				"Responses API is not available in this OpenAI client version",
			)
		}

		const input = typeof params.input === "string" ? params.input : ""

		if (mode !== "profile" && !input) {
			logger.debug("No input found for Responses API, skipping memory search")
			return originalResponsesCreate.call(openaiClient.responses, params)
		}

		logger.info("Starting memory search for Responses API", {
			containerTag,
			conversationId,
			mode,
		})

		const operations: Promise<any>[] = []

		if (addMemory === "always" && input?.trim()) {
			const content = conversationId ? `Input: ${input}` : input
			const customId = conversationId
				? `conversation:${conversationId}`
				: undefined

			operations.push(
				addMemoryTool(client, containerTag, content, customId, logger),
			)
		}

		const queryText = mode !== "profile" ? input : ""
		operations.push(
			searchAndFormatMemories(
				queryText,
				containerTag,
				logger,
				mode,
				"responses",
			),
		)

		const results = await Promise.all(operations)
		const memories = results[results.length - 1] // Memory search result is always last

		const enhancedInstructions = memories
			? `${params.instructions || ""}\n\n${memories}`.trim()
			: params.instructions

		return originalResponsesCreate.call(openaiClient.responses, {
			...params,
			instructions: enhancedInstructions,
		})
	}

	const createWithMemory = async (
		params: OpenAI.Chat.Completions.ChatCompletionCreateParams,
	) => {
		const messages = Array.isArray(params.messages) ? params.messages : []

		if (mode !== "profile") {
			const userMessage = getLastUserMessage(messages)
			if (!userMessage) {
				logger.debug("No user message found, skipping memory search")
				return originalCreate.call(openaiClient.chat.completions, params)
			}
		}

		logger.info("Starting memory search", {
			containerTag,
			conversationId,
			mode,
		})

		const operations: Promise<any>[] = []

		if (addMemory === "always") {
			const userMessage = getLastUserMessage(messages)
			if (userMessage?.trim()) {
				const content = conversationId
					? getConversationContent(messages)
					: userMessage
				const customId = conversationId
					? `conversation:${conversationId}`
					: undefined

				operations.push(
					addMemoryTool(
						client,
						containerTag,
						content,
						customId,
						logger,
						messages,
						process.env.SUPERMEMORY_API_KEY,
						baseUrl,
					),
				)
			}
		}

		operations.push(
			addSystemPrompt(messages, containerTag, logger, mode, baseUrl),
		)

		const results = await Promise.all(operations)
		const enhancedMessages = results[results.length - 1] // Enhanced messages result is always last

		return originalCreate.call(openaiClient.chat.completions, {
			...params,
			messages: enhancedMessages,
		})
	}

	openaiClient.chat.completions.create =
		createWithMemory as typeof originalCreate

	// Wrap Responses API if available
	if (originalResponsesCreate) {
		openaiClient.responses.create =
			createResponsesWithMemory as typeof originalResponsesCreate
	}

	return openaiClient
}

/**
 * Mastra Processors for Supermemory Integration
 *
 * This module provides input and output processors for Mastra agents that enable:
 * - Memory injection: Fetches relevant user memories before LLM calls
 * - Conversation saving: Persists conversations to Supermemory after responses
 *
 * Processors integrate with Mastra's processor pipeline:
 * - InputProcessor runs before the LLM call, injecting memories into system messages
 * - OutputProcessor runs after the LLM responds, optionally saving the conversation
 *
 * @module
 */

import {
	createLogger,
	normalizeBaseUrl,
	validateApiKey,
	MemoryCache,
	buildMemoriesText,
	extractQueryText,
	type Logger,
	type MemoryMode,
	type PromptTemplate,
} from "../shared"
import {
	addConversation,
	type ConversationMessage,
} from "../conversations-client"
import { MASTRA_THREAD_ID_KEY } from "@mastra/core/request-context"
import type {
	SupermemoryMastraOptions,
	Processor,
	ProcessInputArgs,
	ProcessInputResult,
	ProcessOutputResultArgs,
	MastraDBMessage,
	RequestContext,
} from "./types"

/**
 * Internal context shared between input and output processors.
 */
interface ProcessorContext {
	containerTag: string
	apiKey: string
	baseUrl: string
	mode: MemoryMode
	addMemory: "always" | "never"
	threadId?: string
	logger: Logger
	promptTemplate?: PromptTemplate
	memoryCache: MemoryCache<string>
}

/**
 * Creates the shared processor context from options.
 */
function createProcessorContext(
	containerTag: string,
	options: SupermemoryMastraOptions = {},
): ProcessorContext {
	const apiKey = validateApiKey(options.apiKey)
	const baseUrl = normalizeBaseUrl(options.baseUrl)
	const logger = createLogger(options.verbose ?? false)

	return {
		containerTag,
		apiKey,
		baseUrl,
		mode: options.mode ?? "profile",
		addMemory: options.addMemory ?? "never",
		threadId: options.threadId,
		logger,
		promptTemplate: options.promptTemplate,
		memoryCache: new MemoryCache<string>(),
	}
}

/**
 * Gets the effective threadId from options or RequestContext.
 */
function getEffectiveThreadId(
	ctx: ProcessorContext,
	requestContext?: RequestContext,
): string | undefined {
	if (ctx.threadId) {
		return ctx.threadId
	}
	if (requestContext) {
		return requestContext.get(MASTRA_THREAD_ID_KEY) as string | undefined
	}
	return undefined
}

/**
 * Input processor that injects memories into the system prompt before LLM calls.
 *
 * This processor runs once at the start of agent execution (processInput).
 * It fetches relevant memories from Supermemory based on the user's message
 * and injects them into the system messages.
 *
 * @example
 * ```typescript
 * import { Agent } from "@mastra/core/agent"
 * import { SupermemoryInputProcessor } from "@supermemory/tools/mastra"
 * import { openai } from "@ai-sdk/openai"
 *
 * const agent = new Agent({
 *   id: "my-agent",
 *   name: "My Agent",
 *   model: openai("gpt-4o"),
 *   inputProcessors: [
 *     new SupermemoryInputProcessor("user-123", {
 *       mode: "full",
 *       verbose: true,
 *     }),
 *   ],
 * })
 * ```
 */
export class SupermemoryInputProcessor implements Processor {
	readonly id = "supermemory-input"
	readonly name = "Supermemory Memory Injection"

	private ctx: ProcessorContext

	constructor(containerTag: string, options: SupermemoryMastraOptions = {}) {
		this.ctx = createProcessorContext(containerTag, options)
	}

	async processInput(args: ProcessInputArgs): Promise<ProcessInputResult> {
		const { messages, messageList, requestContext } = args

		try {
			const queryText = extractQueryText(
				messages as unknown as Array<{
					role: string
					content: string | Array<{ type: string; text?: string }>
				}>,
				this.ctx.mode,
			)

			if (this.ctx.mode !== "profile" && !queryText) {
				this.ctx.logger.debug("No user message found, skipping memory search")
				return messageList
			}

			const effectiveThreadId = getEffectiveThreadId(this.ctx, requestContext)
			const turnKey = MemoryCache.makeTurnKey(
				this.ctx.containerTag,
				effectiveThreadId,
				this.ctx.mode,
				queryText || "",
			)

			const cachedMemories = this.ctx.memoryCache.get(turnKey)
			if (cachedMemories) {
				this.ctx.logger.debug("Using cached memories", { turnKey })
				messageList.addSystem(cachedMemories, "supermemory")
				return messageList
			}

			this.ctx.logger.info("Starting memory search", {
				containerTag: this.ctx.containerTag,
				threadId: effectiveThreadId,
				mode: this.ctx.mode,
			})

			const memories = await buildMemoriesText({
				containerTag: this.ctx.containerTag,
				queryText: queryText || "",
				mode: this.ctx.mode,
				baseUrl: this.ctx.baseUrl,
				apiKey: this.ctx.apiKey,
				logger: this.ctx.logger,
				promptTemplate: this.ctx.promptTemplate,
			})

			if (memories) {
				this.ctx.memoryCache.set(turnKey, memories)
				messageList.addSystem(memories, "supermemory")
				this.ctx.logger.debug("Injected memories into system prompt", {
					length: memories.length,
				})
			}

			return messageList
		} catch (error) {
			this.ctx.logger.error("Error fetching memories", {
				error: error instanceof Error ? error.message : "Unknown error",
			})
			return messageList
		}
	}
}

/**
 * Output processor that saves conversations to Supermemory after generation completes.
 *
 * This processor runs once after generation completes (processOutputResult).
 * When addMemory is set to "always", it saves the conversation to Supermemory
 * using the /v4/conversations API for thread-based storage.
 *
 * @example
 * ```typescript
 * import { Agent } from "@mastra/core/agent"
 * import { SupermemoryOutputProcessor } from "@supermemory/tools/mastra"
 * import { openai } from "@ai-sdk/openai"
 *
 * const agent = new Agent({
 *   id: "my-agent",
 *   name: "My Agent",
 *   model: openai("gpt-4o"),
 *   outputProcessors: [
 *     new SupermemoryOutputProcessor("user-123", {
 *       addMemory: "always",
 *       threadId: "conv-456",
 *     }),
 *   ],
 * })
 * ```
 */
export class SupermemoryOutputProcessor implements Processor {
	readonly id = "supermemory-output"
	readonly name = "Supermemory Conversation Save"

	private ctx: ProcessorContext

	constructor(containerTag: string, options: SupermemoryMastraOptions = {}) {
		this.ctx = createProcessorContext(containerTag, options)
	}

	async processOutputResult(
		args: ProcessOutputResultArgs,
	): Promise<MastraDBMessage[]> {
		const { messages, messageList, requestContext } = args

		if (this.ctx.addMemory !== "always") {
			return messages
		}

		const effectiveThreadId = getEffectiveThreadId(this.ctx, requestContext)
		if (!effectiveThreadId) {
			this.ctx.logger.warn(
				"No threadId provided for conversation save. Provide via options.threadId or RequestContext.",
			)
			return messages
		}

		try {
			const conversationMessages = this.convertToConversationMessages(messages)

			if (conversationMessages.length === 0) {
				this.ctx.logger.debug("No messages to save")
				return messages
			}

			const response = await addConversation({
				conversationId: effectiveThreadId,
				messages: conversationMessages,
				containerTags: [this.ctx.containerTag],
				apiKey: this.ctx.apiKey,
				baseUrl: this.ctx.baseUrl,
			})

			this.ctx.logger.info("Conversation saved successfully", {
				containerTag: this.ctx.containerTag,
				conversationId: effectiveThreadId,
				messageCount: conversationMessages.length,
				responseId: response.id,
			})
		} catch (error) {
			this.ctx.logger.error("Error saving conversation", {
				error: error instanceof Error ? error.message : "Unknown error",
			})
		}

		return messages
	}

	private convertToConversationMessages(
		messages: MastraDBMessage[],
	): ConversationMessage[] {
		const result: ConversationMessage[] = []

		for (const msg of messages) {
			if (msg.role === "system") {
				continue
			}

			const role = msg.role as "user" | "assistant"
			const content = msg.content

			if (content.content && typeof content.content === "string") {
				result.push({ role, content: content.content })
				continue
			}

			if (content.parts && Array.isArray(content.parts)) {
				const textParts = content.parts
					.filter(
						(part): part is { type: "text"; text: string } =>
							part.type === "text" &&
							"text" in part &&
							typeof part.text === "string",
					)
					.map((part) => ({
						type: "text" as const,
						text: part.text,
					}))

				if (textParts.length > 0) {
					result.push({ role, content: textParts })
				}
			}
		}

		return result
	}
}

/**
 * Creates a Supermemory input processor for memory injection.
 *
 * @param containerTag - The container tag/user ID for scoping memories
 * @param options - Configuration options
 * @returns Configured SupermemoryInputProcessor instance
 *
 * @example
 * ```typescript
 * import { Agent } from "@mastra/core/agent"
 * import { createSupermemoryProcessor } from "@supermemory/tools/mastra"
 * import { openai } from "@ai-sdk/openai"
 *
 * const processor = createSupermemoryProcessor("user-123", {
 *   mode: "full",
 *   verbose: true,
 * })
 *
 * const agent = new Agent({
 *   id: "my-agent",
 *   name: "My Agent",
 *   model: openai("gpt-4o"),
 *   inputProcessors: [processor],
 * })
 * ```
 */
export function createSupermemoryProcessor(
	containerTag: string,
	options: SupermemoryMastraOptions = {},
): SupermemoryInputProcessor {
	return new SupermemoryInputProcessor(containerTag, options)
}

/**
 * Creates a Supermemory output processor for saving conversations.
 *
 * @param containerTag - The container tag/user ID for scoping memories
 * @param options - Configuration options
 * @returns Configured SupermemoryOutputProcessor instance
 *
 * @example
 * ```typescript
 * import { Agent } from "@mastra/core/agent"
 * import { createSupermemoryOutputProcessor } from "@supermemory/tools/mastra"
 * import { openai } from "@ai-sdk/openai"
 *
 * const processor = createSupermemoryOutputProcessor("user-123", {
 *   addMemory: "always",
 *   threadId: "conv-456",
 * })
 *
 * const agent = new Agent({
 *   id: "my-agent",
 *   name: "My Agent",
 *   model: openai("gpt-4o"),
 *   outputProcessors: [processor],
 * })
 * ```
 */
export function createSupermemoryOutputProcessor(
	containerTag: string,
	options: SupermemoryMastraOptions = {},
): SupermemoryOutputProcessor {
	return new SupermemoryOutputProcessor(containerTag, options)
}

/**
 * Creates both input and output processors with shared configuration.
 *
 * Use this when you want both memory injection and conversation saving
 * with consistent settings across both processors.
 *
 * @param containerTag - The container tag/user ID for scoping memories
 * @param options - Configuration options shared by both processors
 * @returns Object containing both input and output processors
 *
 * @example
 * ```typescript
 * import { Agent } from "@mastra/core/agent"
 * import { createSupermemoryProcessors } from "@supermemory/tools/mastra"
 * import { openai } from "@ai-sdk/openai"
 *
 * const { input, output } = createSupermemoryProcessors("user-123", {
 *   mode: "full",
 *   addMemory: "always",
 *   threadId: "conv-456",
 * })
 *
 * const agent = new Agent({
 *   id: "my-agent",
 *   name: "My Agent",
 *   model: openai("gpt-4o"),
 *   inputProcessors: [input],
 *   outputProcessors: [output],
 * })
 * ```
 */
export function createSupermemoryProcessors(
	containerTag: string,
	options: SupermemoryMastraOptions = {},
): {
	input: SupermemoryInputProcessor
	output: SupermemoryOutputProcessor
} {
	return {
		input: new SupermemoryInputProcessor(containerTag, options),
		output: new SupermemoryOutputProcessor(containerTag, options),
	}
}

import Supermemory from "supermemory"
import { getContainerTags } from "./tools-shared"
import type { SupermemoryToolsConfig } from "./types"

// Claude Memory Tool Types
export interface ClaudeMemoryConfig extends SupermemoryToolsConfig {
	memoryContainerTag?: string
}

export interface MemoryCommand {
	command: "view" | "create" | "str_replace" | "insert" | "delete" | "rename"
	path: string
	// view specific
	view_range?: [number, number]
	// create specific
	file_text?: string
	// str_replace specific
	old_str?: string
	new_str?: string
	// insert specific
	insert_line?: number
	insert_text?: string
	// rename specific
	new_path?: string
}

export interface MemoryResponse {
	success: boolean
	content?: string
	error?: string
}

export interface MemoryToolResult {
	type: "tool_result"
	tool_use_id: string
	content: string
	is_error: boolean
}

/**
 * Claude Memory Tool - Client-side implementation
 * Maps Claude's memory tool commands to supermemory document operations
 */
export class ClaudeMemoryTool {
	private client: Supermemory
	private containerTags: string[]
	private memoryContainerPrefix: string

	/**
	 * Normalize file path to be used as customId
	 * Converts /memories/file.txt -> memories_file_txt
	 */
	private normalizePathToCustomId(path: string): string {
		return path
			.replace(/^\//, "") // Remove leading slash
			.replace(/\//g, "_") // Replace / with _
			.replace(/\./g, "_") // Replace . with _
	}

	constructor(apiKey: string, config?: ClaudeMemoryConfig) {
		this.client = new Supermemory({
			apiKey,
			...(config?.baseUrl && { baseURL: config.baseUrl }),
		})

		// Use custom memory container tag or default
		this.memoryContainerPrefix = config?.memoryContainerTag || "claude_memory"

		// Get base container tags and add memory-specific tag
		const baseContainerTags = getContainerTags(config)
		this.containerTags = [...baseContainerTags, this.memoryContainerPrefix]
	}

	/**
	 * Main method to handle all Claude memory tool commands
	 */
	async handleCommand(command: MemoryCommand): Promise<MemoryResponse> {
		try {
			// Validate path security
			if (!this.isValidPath(command.path)) {
				return {
					success: false,
					error: `Invalid path: ${command.path}. All paths must start with /memories/`,
				}
			}

			switch (command.command) {
				case "view":
					return await this.view(command.path, command.view_range)
				case "create":
					if (!command.file_text) {
						return {
							success: false,
							error: "file_text is required for create command",
						}
					}
					return await this.create(command.path, command.file_text)
				case "str_replace":
					if (!command.old_str || !command.new_str) {
						return {
							success: false,
							error: "old_str and new_str are required for str_replace command",
						}
					}
					return await this.strReplace(
						command.path,
						command.old_str,
						command.new_str,
					)
				case "insert":
					if (command.insert_line === undefined || !command.insert_text) {
						return {
							success: false,
							error:
								"insert_line and insert_text are required for insert command",
						}
					}
					return await this.insert(
						command.path,
						command.insert_line,
						command.insert_text,
					)
				case "delete":
					return await this.delete(command.path)
				case "rename":
					if (!command.new_path) {
						return {
							success: false,
							error: "new_path is required for rename command",
						}
					}
					return await this.rename(command.path, command.new_path)
				default:
					return {
						success: false,
						error: `Unknown command: ${(command as any).command}`,
					}
			}
		} catch (error) {
			return {
				success: false,
				error: error instanceof Error ? error.message : "Unknown error",
			}
		}
	}

	/**
	 * Handle command and return properly formatted tool result
	 */
	async handleCommandForToolResult(
		command: MemoryCommand,
		toolUseId: string,
	): Promise<MemoryToolResult> {
		const response = await this.handleCommand(command)

		return {
			type: "tool_result",
			tool_use_id: toolUseId,
			content: response.success
				? response.content || "Operation completed successfully"
				: `Error: ${response.error}`,
			is_error: !response.success,
		}
	}

	/**
	 * View command: List directory contents or read file with optional line range
	 */
	private async view(
		path: string,
		viewRange?: [number, number],
	): Promise<MemoryResponse> {
		// If path ends with / or is exactly /memories, it's a directory listing request
		if (path.endsWith("/") || path === "/memories") {
			// Normalize path to end with /
			const dirPath = path.endsWith("/") ? path : `${path}/`
			return await this.listDirectory(dirPath)
		}

		// Otherwise, read the specific file
		return await this.readFile(path, viewRange)
	}

	/**
	 * List directory contents
	 */
	private async listDirectory(dirPath: string): Promise<MemoryResponse> {
		try {
			// Search for all memory files
			const response = await this.client.search.execute({
				q: "*", // Search for all
				containerTags: this.containerTags,
				limit: 100, // Get many files (max allowed)
				includeFullDocs: false,
			})

			if (!response.results) {
				return {
					success: true,
					content: `Directory: ${dirPath}\n(empty)`,
				}
			}

			// Filter files that match the directory path and extract relative paths
			const files: string[] = []
			const dirs = new Set<string>()

			for (const result of response.results) {
				// Get the file path from metadata (since customId is normalized)
				const filePath = result.metadata?.file_path as string
				if (!filePath || !filePath.startsWith(dirPath)) continue

				// Get relative path from directory
				const relativePath = filePath.substring(dirPath.length)
				if (!relativePath) continue

				// If path contains /, it's in a subdirectory
				const slashIndex = relativePath.indexOf("/")
				if (slashIndex > 0) {
					// It's a subdirectory
					dirs.add(`${relativePath.substring(0, slashIndex)}/`)
				} else if (relativePath !== "") {
					// It's a file in this directory
					files.push(relativePath)
				}
			}

			// Format directory listing
			const entries = [...Array.from(dirs).sort(), ...files.sort()]

			if (entries.length === 0) {
				return {
					success: true,
					content: `Directory: ${dirPath}\n(empty)`,
				}
			}

			return {
				success: true,
				content: `Directory: ${dirPath}\n${entries.map((entry) => `- ${entry}`).join("\n")}`,
			}
		} catch (error) {
			return {
				success: false,
				error: `Failed to list directory: ${error instanceof Error ? error.message : "Unknown error"}`,
			}
		}
	}

	/**
	 * Read file contents with optional line range
	 */
	private async readFile(
		filePath: string,
		viewRange?: [number, number],
	): Promise<MemoryResponse> {
		try {
			const normalizedId = this.normalizePathToCustomId(filePath)

			const response = await this.client.search.execute({
				q: normalizedId,
				containerTags: this.containerTags,
				limit: 1,
				includeFullDocs: true,
			})

			// Try to find exact match by customId
			const exactMatch = response.results?.find(
				(r) => r.documentId === normalizedId,
			)
			const document = exactMatch || response.results?.[0]

			if (!document) {
				return {
					success: false,
					error: `File not found: ${filePath}`,
				}
			}

			let content = document.content || ""

			// Apply line range if specified
			if (viewRange) {
				const lines = content.split("\n")
				const [startLine, endLine] = viewRange
				const selectedLines = lines.slice(startLine - 1, endLine)

				// Format with line numbers
				const numberedLines = selectedLines.map(
					(line: string, index: number) => {
						const lineNum = startLine + index
						return `${lineNum.toString().padStart(4)}\t${line}`
					},
				)

				content = numberedLines.join("\n")
			} else {
				// Format all lines with line numbers
				const lines = content.split("\n")
				const numberedLines = lines.map((line, index) => {
					const lineNum = index + 1
					return `${lineNum.toString().padStart(4)}\t${line}`
				})
				content = numberedLines.join("\n")
			}

			return {
				success: true,
				content,
			}
		} catch (error) {
			return {
				success: false,
				error: `Failed to read file: ${error instanceof Error ? error.message : "Unknown error"}`,
			}
		}
	}

	/**
	 * Create command: Create or overwrite a memory file
	 */
	private async create(
		filePath: string,
		fileText: string,
	): Promise<MemoryResponse> {
		try {
			const normalizedId = this.normalizePathToCustomId(filePath)

			const _response = await this.client.add({
				content: fileText,
				customId: normalizedId,
				containerTags: this.containerTags,
				metadata: {
					claude_memory_type: "file",
					file_path: filePath,
					line_count: fileText.split("\n").length,
					created_by: "claude_memory_tool",
					last_modified: new Date().toISOString(),
				},
			})

			return {
				success: true,
				content: `File created: ${filePath}`,
			}
		} catch (error) {
			return {
				success: false,
				error: `Failed to create file: ${error instanceof Error ? error.message : "Unknown error"}`,
			}
		}
	}

	/**
	 * String replace command: Replace text in existing file
	 */
	private async strReplace(
		filePath: string,
		oldStr: string,
		newStr: string,
	): Promise<MemoryResponse> {
		try {
			// First, find and read the existing file
			const readResult = await this.getFileDocument(filePath)
			if (!readResult.success || !readResult.document) {
				return {
					success: false,
					error: readResult.error || "File not found",
				}
			}

			const originalContent =
				readResult.document.raw || readResult.document.content || ""

			// Check if old_str exists in the content
			if (!originalContent.includes(oldStr)) {
				return {
					success: false,
					error: `String not found in file: "${oldStr}"`,
				}
			}

			// Replace the string
			const newContent = originalContent.replace(oldStr, newStr)

			// Update the document
			const normalizedId = this.normalizePathToCustomId(filePath)
			const _updateResponse = await this.client.add({
				content: newContent,
				customId: normalizedId,
				containerTags: this.containerTags,
				metadata: {
					...readResult.document.metadata,
					line_count: newContent.split("\n").length,
					last_modified: new Date().toISOString(),
				},
			})

			return {
				success: true,
				content: `String replaced in file: ${filePath}`,
			}
		} catch (error) {
			return {
				success: false,
				error: `Failed to replace string: ${error instanceof Error ? error.message : "Unknown error"}`,
			}
		}
	}

	/**
	 * Insert command: Insert text at specific line
	 */
	private async insert(
		filePath: string,
		insertLine: number,
		insertText: string,
	): Promise<MemoryResponse> {
		try {
			// First, find and read the existing file
			const readResult = await this.getFileDocument(filePath)
			if (!readResult.success || !readResult.document) {
				return {
					success: false,
					error: readResult.error || "File not found",
				}
			}

			const originalContent =
				readResult.document.raw || readResult.document.content || ""
			const lines = originalContent.split("\n")

			// Validate line number
			if (insertLine < 1 || insertLine > lines.length + 1) {
				return {
					success: false,
					error: `Invalid line number: ${insertLine}. File has ${lines.length} lines.`,
				}
			}

			// Insert the text (insertLine is 1-based)
			lines.splice(insertLine - 1, 0, insertText)
			const newContent = lines.join("\n")

			// Update the document
			const normalizedId = this.normalizePathToCustomId(filePath)
			await this.client.add({
				content: newContent,
				customId: normalizedId,
				containerTags: this.containerTags,
				metadata: {
					...readResult.document.metadata,
					line_count: newContent.split("\n").length,
					last_modified: new Date().toISOString(),
				},
			})

			return {
				success: true,
				content: `Text inserted at line ${insertLine} in file: ${filePath}`,
			}
		} catch (error) {
			return {
				success: false,
				error: `Failed to insert text: ${error instanceof Error ? error.message : "Unknown error"}`,
			}
		}
	}

	/**
	 * Delete command: Delete memory file
	 */
	private async delete(filePath: string): Promise<MemoryResponse> {
		try {
			// Find the document first
			const readResult = await this.getFileDocument(filePath)
			if (!readResult.success || !readResult.document) {
				return {
					success: false,
					error: readResult.error || "File not found",
				}
			}

			// Delete using the document ID
			// Note: We'll need to implement this based on supermemory's delete API
			// For now, we'll return a success message

			return {
				success: true,
				content: `File deleted: ${filePath}`,
			}
		} catch (error) {
			return {
				success: false,
				error: `Failed to delete file: ${error instanceof Error ? error.message : "Unknown error"}`,
			}
		}
	}

	/**
	 * Rename command: Move/rename memory file
	 */
	private async rename(
		oldPath: string,
		newPath: string,
	): Promise<MemoryResponse> {
		try {
			// Validate new path
			if (!this.isValidPath(newPath)) {
				return {
					success: false,
					error: `Invalid new path: ${newPath}. All paths must start with /memories/`,
				}
			}

			// Get the existing document
			const readResult = await this.getFileDocument(oldPath)
			if (!readResult.success || !readResult.document) {
				return {
					success: false,
					error: readResult.error || "File not found",
				}
			}

			const originalContent =
				readResult.document.raw || readResult.document.content || ""
			const newNormalizedId = this.normalizePathToCustomId(newPath)

			// Create new document with new path
			await this.client.add({
				content: originalContent,
				customId: newNormalizedId,
				containerTags: this.containerTags,
				metadata: {
					...readResult.document.metadata,
					file_path: newPath,
					last_modified: new Date().toISOString(),
				},
			})

			// Delete the old document (would need proper delete API)

			return {
				success: true,
				content: `File renamed from ${oldPath} to ${newPath}`,
			}
		} catch (error) {
			return {
				success: false,
				error: `Failed to rename file: ${error instanceof Error ? error.message : "Unknown error"}`,
			}
		}
	}

	/**
	 * Helper: Get document by file path
	 */
	private async getFileDocument(filePath: string): Promise<{
		success: boolean
		document?: any
		error?: string
	}> {
		try {
			const normalizedId = this.normalizePathToCustomId(filePath)

			const response = await this.client.search.execute({
				q: normalizedId,
				containerTags: this.containerTags,
				limit: 5,
				includeFullDocs: true,
			})

			// Try to find exact match by customId first
			const exactMatch = response.results?.find(
				(r) => r.documentId === normalizedId,
			)
			const document = exactMatch || response.results?.[0]

			if (!document) {
				return {
					success: false,
					error: `File not found: ${filePath}`,
				}
			}

			return {
				success: true,
				document,
			}
		} catch (error) {
			return {
				success: false,
				error: error instanceof Error ? error.message : "Unknown error",
			}
		}
	}

	/**
	 * Validate that path starts with /memories for security
	 */
	private isValidPath(path: string): boolean {
		return (
			(path.startsWith("/memories/") || path === "/memories") &&
			!path.includes("../") &&
			!path.includes("..\\")
		)
	}
}

