149→// ListStrategicMemory returns recent distilled execution insights, newest
150→// first. A limit <= 0 returns every row.
151→func ListStrategicMemory(db *sql.DB, limit int) ([]StrategicMemory, error) {
152→	query := `
153→		SELECT
154→			id,
155→			category,
156→			summary,
157→			affected_skills,
158→			evidence,
159→			source,
160→			source_key,
161→			priority,
162→			first_seen_at,
163→			last_seen_at,
164→			occurrence_count,
165→			created_at,
166→			updated_at
167→		FROM strategic_memory
168→		ORDER BY last_seen_at DESC, priority DESC, id DESC`
169→	args := []any{}
170→	if limit > 0 {
171→		query += ` LIMIT ?`
172→		args = append(args, limit)
173→	}
174→
175→	rows, err := db.Query(query, args...)
176→	if err != nil {
177→		return nil, fmt.Errorf("listing strategic memory: %w", err)
178→	}
179→	defer rows.Close()
180→
181→	var items []StrategicMemory
182→	for rows.Next() {
183→		var (
184→			item               StrategicMemory
185→			affectedSkillsJSON string
186→			evidenceJSON       string
187→		)
188→		if err := rows.Scan(
189→			&item.ID,
190→			&item.Category,
191→			&item.Summary,
192→			&affectedSkillsJSON,
193→			&evidenceJSON,
194→			&item.Source,
195→			&item.SourceKey,
196→			&item.Priority,
197→			&item.FirstSeenAt,
198→			&item.LastSeenAt,
199→			&item.OccurrenceCount,
200→			&item.CreatedAt,
201→			&item.UpdatedAt,
202→		); err != nil {
203→			return nil, fmt.Errorf("scanning strategic memory: %w", err)
204→		}
205→		if strings.TrimSpace(affectedSkillsJSON) != "" {
206→			_ = json.Unmarshal([]byte(affectedSkillsJSON), &item.AffectedSkills)
207→		}
208→		if strings.TrimSpace(evidenceJSON) != "" {
209→			_ = json.Unmarshal([]byte(evidenceJSON), &item.Evidence)
210→		}
211→		items = append(items, item)
212→	}
213→	return items, rows.Err()
214→}
