344→func shouldFlagEmailDelta(basis, delta int) bool {
345→	if delta <= 0 {
346→		return false
347→	}
348→	if basis == 0 {
349→		return true
350→	}
351→	return delta >= skillEmailStaleThreshold
352→}
353→
354→func shouldFlagLearningDelta(basis, delta int) bool {
355→	if delta <= 0 {
356→		return false
357→	}
358→	if basis == 0 {
359→		return true
360→	}
361→	return delta >= skillLearningStaleThreshold
362→}
363→
364→func happenedAfter(lhs, rhs string) bool {
365→	if strings.TrimSpace(lhs) == "" {
366→		return false
367→	}
368→	if strings.TrimSpace(rhs) == "" {
369→		return true
370→	}
371→	left, leftOK := parseSQLiteTime(lhs)
372→	right, rightOK := parseSQLiteTime(rhs)
373→	if leftOK && rightOK {
374→		return left.After(right)
375→	}
376→	return lhs > rhs
377→}
378→
379→func parseSQLiteTime(value string) (time.Time, bool) {
380→	for _, layout := range []string{"2006-01-02 15:04:05", time.RFC3339, time.RFC3339Nano} {
381→		parsed, err := time.Parse(layout, value)
382→		if err == nil {
383→			return parsed, true
384→		}
385→	}
386→	return time.Time{}, false
387→}
388→
389→func prettyCategories(categories []string) []string {
390→	pretty := make([]string, 0, len(categories))
391→	for _, category := range categories {
392→		switch category {
393→		case "positive_replies":
394→			pretty = append(pretty, "positive replies")
395→		case "reply_friction":
396→			pretty = append(pretty, "reply friction")
397→		case "reply_attention":
398→			pretty = append(pretty, "reply attention")
399→		case "delivery_risk":
400→			pretty = append(pretty, "delivery risk")
401→		case "suppression_growth":
402→			pretty = append(pretty, "suppression growth")
403→		case "sequence_outcomes":
404→			pretty = append(pretty, "sequence outcomes")
405→		default:
406→			pretty = append(pretty, strings.ReplaceAll(category, "_", " "))
407→		}
408→	}
409→	sort.Strings(pretty)
410→	return pretty
411→}
412→
413→func uniqueSortedStrings(values []string) []string {
414→	seen := make(map[string]struct{}, len(values))
415→	var result []string
416→	for _, value := range values {
417→		value = strings.TrimSpace(value)
418→		if value == "" {
419→			continue
420→		}
421→		if _, ok := seen[value]; ok {
422→			continue
423→		}
424→		seen[value] = struct{}{}
425→		result = append(result, value)
426→	}
427→	sort.Strings(result)
428→	return result
429→}
430→
431→func pluralize(count int) string {
432→	if count == 1 {
433→		return ""
434→	}
435→	return "s"
436→}
437→
438→func activePtr(ok bool, value activeSkillVersion) *activeSkillVersion {
439→	if !ok {
440→		return nil
441→	}
442→	copy := value
443→	return &copy
444→}
