158→func (e *Engine) replyClassificationCounts(previousVersion, currentVersion int64) (map[string]int, error) {
159→	rows, err := e.db.Query(`
160→		SELECT classification, COUNT(*)
161→		FROM reply_events
162→		WHERE sync_version > ? AND sync_version <= ?
163→		GROUP BY classification`,
164→		previousVersion,
165→		currentVersion,
166→	)
167→	if err != nil {
168→		return nil, fmt.Errorf("counting reply classifications: %w", err)
169→	}
170→	defer rows.Close()
171→
172→	counts := map[string]int{}
173→	for rows.Next() {
174→		var classification string
175→		var count int
176→		if err := rows.Scan(&classification, &count); err != nil {
177→			return nil, fmt.Errorf("scanning reply classification count: %w", err)
178→		}
179→		counts[normalizeClassification(classification)] = count
180→	}
181→	return counts, rows.Err()
182→}
183→
184→func normalizeClassification(value string) string {
185→	value = strings.ToLower(strings.TrimSpace(value))
186→	value = strings.ReplaceAll(value, "-", "_")
187→	value = strings.ReplaceAll(value, " ", "_")
188→	return value
189→}
190→
191→func sumReplyCounts(counts map[string]int, keys ...string) int {
192→	total := 0
193→	for _, key := range keys {
194→		total += counts[key]
195→	}
196→	return total
197→}
198→
199→func filterReplyCounts(counts map[string]int, keys ...string) map[string]int {
200→	filtered := map[string]int{}
201→	for _, key := range keys {
202→		if counts[key] > 0 {
203→			filtered[key] = counts[key]
204→		}
205→	}
206→	return filtered
207→}
208→
209→func mergeEvidence(base, overlay map[string]any) map[string]any {
210→	merged := map[string]any{}
211→	for key, value := range base {
212→		merged[key] = value
213→	}
214→	for key, value := range overlay {
215→		merged[key] = value
216→	}
217→	return merged
218→}
219→
220→func syncPluralSuffix(count int, forms ...string) string {
221→	if len(forms) == 2 {
222→		if count == 1 {
223→			return forms[0]
224→		}
225→		return forms[1]
226→	}
227→	if count == 1 {
228→		return ""
229→	}
230→	return "s"
231→}
