 11→const configFile = ".nurge/config.json"
 12→
 13→// ConnectorState holds the state of a single connected service.
 14→type ConnectorState struct {
 15→	Connected   bool   `json:"connected"`
 16→	ConnectedAt string `json:"connected_at,omitempty"`
 17→	Account     string `json:"account,omitempty"`
 18→	Type        string `json:"type"` // "crm" or "email"
 19→}
 20→
 21→// Config is the top-level nurge configuration.
 22→type Config struct {
 23→	Version        int                        `json:"version"`
 24→	CreatedAt      string                     `json:"created_at"`
 25→	Connectors     map[string]ConnectorState  `json:"connectors"`
 26→	SetupCompleted bool                       `json:"setup_completed"`
 27→	Settings       map[string]string          `json:"settings,omitempty"`
 28→}
 29→
 30→// Path returns the path to config.json.
 31→func Path() string {
 32→	return configFile
 33→}
 34→
 35→// Default returns a new Config with default values.
 36→func Default() *Config {
 37→	return &Config{
 38→		Version:        1,
 39→		CreatedAt:      time.Now().UTC().Format(time.RFC3339),
 40→		Connectors:     make(map[string]ConnectorState),
 41→		SetupCompleted: false,
 42→	}
 43→}
 44→
 45→// Load reads config from disk.
 46→func Load() (*Config, error) {
 47→	data, err := os.ReadFile(configFile)
 48→	if err != nil {
 49→		return nil, fmt.Errorf("reading config: %w", err)
 50→	}
 51→	var cfg Config
 52→	if err := json.Unmarshal(data, &cfg); err != nil {
 53→		return nil, fmt.Errorf("parsing config: %w", err)
 54→	}
 55→	if cfg.Connectors == nil {
 56→		cfg.Connectors = make(map[string]ConnectorState)
 57→	}
 58→	return &cfg, nil
 59→}
 60→
 61→// Write saves config to disk.
 62→func Write(cfg *Config) error {
 63→	data, err := json.MarshalIndent(cfg, "", "  ")
 64→	if err != nil {
 65→		return fmt.Errorf("marshaling config: %w", err)
 66→	}
 67→	if err := os.WriteFile(configFile, data, 0644); err != nil {
