  1→package project
  2→
  3→import (
  4→	"encoding/json"
  5→	"fmt"
  6→	"os"
  7→	"path/filepath"
  8→)
  9→
 10→type hooksStep struct{}
 11→
 12→func (s *hooksStep) Name() string { return "Claude Code hooks installed" }
 13→
 14→// hookEntry is a single hook command within a matcher group.
 15→type hookEntry struct {
 16→	command string
 17→}
 18→
 19→// hookGroup defines a matcher group with its hooks for a given event.
 20→type hookGroup struct {
 21→	event   string
 22→	matcher string
 23→	hooks   []hookEntry
 24→}
 25→
 26→// requiredHookGroups defines all hook groups nurge needs installed.
 27→// Hooks sharing the same event+matcher are grouped together (matching entire.io's pattern).
 28→var requiredHookGroups = []hookGroup{
 29→	{
 30→		event:   "PostToolUse",
 31→		matcher: "Bash",
 32→		hooks:   []hookEntry{{command: "nurge hook post-tool-use"}},
 33→	},
 34→	{
 35→		event:   "SessionStart",
 36→		matcher: "",
 37→		hooks:   []hookEntry{{command: "nurge hook session-start"}},
 38→	},
 39→	{
 40→		event:   "UserPromptSubmit",
 41→		matcher: "",
 42→		hooks:   []hookEntry{{command: "nurge hook user-prompt"}},
 43→	},
 44→	{
 45→		event:   "Stop",
 46→		matcher: "",
 47→		hooks:   []hookEntry{{command: "nurge hook stop"}},
 48→	},
 49→	{
 50→		event:   "SessionEnd",
 51→		matcher: "",
 52→		hooks:   []hookEntry{{command: "nurge hook session-end"}},
 53→	},
 54→}
 55→
 56→func (s *hooksStep) Done() (bool, error) {
 57→	data, err := os.ReadFile(claudeSettingsPath())
 58→	if err != nil {
 59→		if os.IsNotExist(err) {
 60→			return false, nil
 61→		}
 62→		return false, err
 63→	}
 64→
 65→	var settings map[string]any
 66→	if err := json.Unmarshal(data, &settings); err != nil {
 67→		return false, nil
 68→	}
 69→
 70→	hooks, ok := settings["hooks"].(map[string]any)
 71→	if !ok {
 72→		return false, nil
 73→	}
 74→
 75→	for _, g := range requiredHookGroups {
 76→		for _, h := range g.hooks {
 77→			if !hookCommandExists(hooks, g.event, h.command) {
 78→				return false, nil
 79→			}
 80→		}
 81→	}
 82→	return true, nil
 83→}
 84→
 85→func (s *hooksStep) Run() error {
 86→	settingsPath := claudeSettingsPath()
 87→
 88→	if err := os.MkdirAll(filepath.Dir(settingsPath), 0755); err != nil {
 89→		return fmt.Errorf("creating .claude/: %w", err)
 90→	}
 91→
 92→	// Load existing settings or start fresh
 93→	settings := make(map[string]any)
 94→	if data, err := os.ReadFile(settingsPath); err == nil {
 95→		json.Unmarshal(data, &settings) // ignore error, start fresh if corrupt
 96→	}
 97→
 98→	hooks, _ := settings["hooks"].(map[string]any)
 99→	if hooks == nil {
100→		hooks = make(map[string]any)
101→	}
102→
103→	for _, g := range requiredHookGroups {
104→		// Collect commands that are missing
105→		var missing []hookEntry
106→		for _, h := range g.hooks {
107→			if !hookCommandExists(hooks, g.event, h.command) {
108→				missing = append(missing, h)
109→			}
110→		}
111→		if len(missing) == 0 {
112→			continue
113→		}
114→
115→		// Find existing matcher entry for this event+matcher, or create one
116→		eventHooks, _ := hooks[g.event].([]any)
117→		matcherIdx := -1
118→		for i, item := range eventHooks {
119→			m, ok := item.(map[string]any)
120→			if !ok {
121→				continue
122→			}
123→			if matcher, _ := m["matcher"].(string); matcher == g.matcher {
124→				matcherIdx = i
125→				break
126→			}
127→		}
128→
129→		if matcherIdx >= 0 {
130→			entry := eventHooks[matcherIdx].(map[string]any)
131→			innerHooks, _ := entry["hooks"].([]any)
132→			for _, h := range missing {
133→				innerHooks = append(innerHooks, hookEntryJSON(h.command))
134→			}
135→			entry["hooks"] = innerHooks
136→		} else {
137→			var innerHooks []any
138→			for _, h := range g.hooks {
139→				innerHooks = append(innerHooks, hookEntryJSON(h.command))
140→			}
141→			entry := map[string]any{
142→				"matcher": g.matcher,
143→				"hooks":   innerHooks,
144→			}
145→			eventHooks = append(eventHooks, entry)
146→		}
147→		hooks[g.event] = eventHooks
148→	}
149→
150→	settings["hooks"] = hooks
151→
152→	// Sync permissions into the settings
153→	syncPermissionsInto(settings)
154→
155→	data, err := json.MarshalIndent(settings, "", "  ")
156→	if err != nil {
157→		return fmt.Errorf("marshaling settings: %w", err)
158→	}
159→
160→	if err := os.WriteFile(settingsPath, data, 0644); err != nil {
161→		return fmt.Errorf("writing settings: %w", err)
162→	}
163→
164→	return nil
165→}
166→
167→// hookCommandExists checks if a specific command already exists under the given event key.
168→func hookCommandExists(hooks map[string]any, event, command string) bool {
169→	arr, ok := hooks[event].([]any)
170→	if !ok {
171→		return false
172→	}
173→	for _, item := range arr {
174→		m, ok := item.(map[string]any)
175→		if !ok {
176→			continue
177→		}
178→		innerHooks, ok := m["hooks"].([]any)
179→		if !ok {
180→			continue
181→		}
182→		for _, h := range innerHooks {
183→			hm, ok := h.(map[string]any)
184→			if !ok {
185→				continue
186→			}
187→			if cmd, ok := hm["command"].(string); ok && cmd == command {
188→				return true
189→			}
190→		}
191→	}
192→	return false
193→}
194→
195→func containsString(arr []any, s string) bool {
196→	for _, v := range arr {
197→		if str, ok := v.(string); ok && str == s {
198→			return true
199→		}
200→	}
201→	return false
202→}
203→
204→func hookEntryJSON(command string) map[string]any {
205→	return map[string]any{"type": "command", "command": command}
206→}
207→
208→func claudeSettingsPath() string {
209→	return filepath.Join(".claude", "settings.json")
210→}
211→
212→// RequiredPermissions lists all allow-rules nurge needs in .claude/settings.json.
213→// Kept in one place so init and session-start sync stay consistent.
214→var RequiredPermissions = []string{
215→	"Bash(nurge *)",
216→	"Bash(git *)",
217→	"Bash(go *)",
218→	"Bash(curl *)",
219→	"Bash(dig *)",
220→	"Bash(gh *)",
221→	"Bash(which *)",
222→	"Bash(ls *)",
223→	"Bash(mkdir *)",
224→	"Bash(cp *)",
225→	"Bash(mv *)",
226→	"Read",
227→	"Edit",
228→	"Write",
229→	"WebFetch",
230→	"WebSearch",
231→}
232→
233→// syncPermissionsInto ensures all RequiredPermissions are present in the
234→// given settings map (mutates in place).
235→func syncPermissionsInto(settings map[string]any) {
236→	permissions, _ := settings["permissions"].(map[string]any)
237→	if permissions == nil {
238→		permissions = make(map[string]any)
239→	}
240→	allow, _ := permissions["allow"].([]any)
241→	for _, perm := range RequiredPermissions {
242→		if !containsString(allow, perm) {
243→			allow = append(allow, perm)
244→		}
245→	}
246→	permissions["allow"] = allow
247→	settings["permissions"] = permissions
248→}
249→
250→// SyncPermissions reads .claude/settings.json, adds any missing required
251→// permissions, and writes the file back. Safe to call on every session start.
252→// Returns (added, error) where added is the number of new permissions inserted.
253→func SyncPermissions() (int, error) {
254→	settingsPath := claudeSettingsPath()
255→
256→	settings := make(map[string]any)
257→	if data, err := os.ReadFile(settingsPath); err == nil {
258→		json.Unmarshal(data, &settings)
259→	} else if os.IsNotExist(err) {
260→		return 0, nil
261→	} else {
262→		return 0, err
263→	}
264→
265→	before := countAllowPermissions(settings)
266→	syncPermissionsInto(settings)
267→	added := countAllowPermissions(settings) - before
268→	if added == 0 {
269→		return 0, nil
270→	}
271→
272→	data, err := json.MarshalIndent(settings, "", "  ")
273→	if err != nil {
274→		return 0, fmt.Errorf("marshaling settings: %w", err)
275→	}
276→	if err := os.WriteFile(settingsPath, data, 0644); err != nil {
277→		return 0, fmt.Errorf("writing settings: %w", err)
278→	}
279→	return added, nil
280→}
281→
282→func countAllowPermissions(settings map[string]any) int {
283→	permissions, _ := settings["permissions"].(map[string]any)
284→	if permissions == nil {
285→		return 0
286→	}
287→	allow, _ := permissions["allow"].([]any)
288→	return len(allow)
289→}
