178→// hookOutput is the JSON structure Claude Code expects from hook stdout.
179→type hookOutput struct {
180→	SystemMessage   string           `json:"systemMessage,omitempty"`
181→	HookSpecificOut *hookSpecificOut `json:"hookSpecificOutput,omitempty"`
182→}
183→
184→type hookSpecificOut struct {
185→	HookEventName     string `json:"hookEventName"`
186→	AdditionalContext string `json:"additionalContext,omitempty"`
187→}
188→
189→// runSessionStart outputs JSON with systemMessage (visible banner) and
190→// additionalContext (LLM context) for the SessionStart hook.
191→// Also captures the session in DB + log.
192→func runSessionStart() error {
193→	// Read stdin (Claude Code sends session info)
194→	input, _ := session.ReadStdin()
195→
196→	// Sync permissions — ensures existing users get any new permissions
197→	// added in later versions. Graceful — never fails the hook.
198→	project.SyncPermissions()
199→
200→	syncReport := attemptSessionStartSync()
201→
202→	// Auto-update check (non-blocking, cached)
203→	updateMsg := checkAndAutoUpdate()
204→
205→	s := gatherStatus()
206→	s.startSync = syncReport
207→
208→	// Capture session + sync event in a single DB open (graceful — don't fail the hook)
209→	if input != nil && input.SessionID != "" && db.Exists() {
210→		if d, err := db.Open(); err == nil {
211→	
212→			session.CreateSession(d, input.SessionID, input.Model, input.Source, input.TranscriptPath)
213→			session.AddEvent(d, input.SessionID, "session_start", input)
214→			if syncReport != nil && syncReport.Attempted {
215→				session.AddEvent(d, input.SessionID, "sync_pull", syncReport)
216→			}
217→			d.Close()
218→		}
219→		session.Logger().Info("session-start", "session_id", input.SessionID, "model", input.Model)
220→		session.FlushLog()
221→	}
222→
223→	banner := buildBanner(s)
224→	if updateMsg != "" {
225→		banner += "\n  " + updateMsg
226→	}
227→	context := buildPromptContext(s)
228→
229→	out := hookOutput{
230→		SystemMessage: banner,
231→		HookSpecificOut: &hookSpecificOut{
232→			HookEventName:     "SessionStart",
233→			AdditionalContext: context,
234→		},
235→	}
236→
237→	enc := json.NewEncoder(os.Stdout)
238→	return enc.Encode(out)
239→}
