316→func buildBanner(s *sessionStatus) string {
317→	var b strings.Builder
318→	ver := fmt.Sprintf("nurge %s", buildVersion)
319→
320→	// Line 1: Powered by Nurge
321→	b.WriteString("\n\nPowered by Nurge\n")
322→	// Line 2: Version
323→	fmt.Fprintf(&b, "  %s\n", ver)
324→
325→	if !s.configLoaded {
326→		b.WriteString("  Run: nurge to get started")
327→		return b.String()
328→	}
329→
330→	// --- Pre-setup: no connectors yet ---
331→	hasConnectors := false
332→	for _, c := range s.connectors {
333→		if c.Connected {
334→			hasConnectors = true
335→			break
336→		}
337→	}
338→	if !hasConnectors {
339→		b.WriteString("  Run /nurge:setup to connect your email and get started.")
340→		return b.String()
341→	}
342→
343→	// --- Setup in progress ---
344→	if !s.setupCompleted {
345→		name := s.settings["user.name"]
346→		if name != "" {
347→			fmt.Fprintf(&b, "  Hey %s, setup in progress.\n", name)
348→		} else {
349→			b.WriteString("  Setup in progress.\n")
350→		}
351→		b.WriteString("  Run /nurge:setup to continue where you left off.")
352→		return b.String()
353→	}
354→
355→	// --- Post-setup: compact rotating dashboard ---
356→	name := s.settings["user.name"]
357→	if name != "" {
358→		fmt.Fprintf(&b, "  Hey %s\n", name)
359→	}
360→
361→	if syncLine := buildSyncBannerLine(s.startSync); syncLine != "" {
362→		fmt.Fprintf(&b, "  %s\n", syncLine)
363→	}
364→	if refreshLine := buildSkillRefreshBannerLine(s.staleSkills); refreshLine != "" {
365→		fmt.Fprintf(&b, "  %s\n", refreshLine)
366→	}
367→
368→	// Always show: KPI progress (the one thing that matters most)
369→	if s.weeklyStats != nil && s.weeklyStats.OutboundSent > 0 {
370→		fmt.Fprintf(&b, "  This week: %d emails sent", s.weeklyStats.OutboundSent)
371→		if s.weeklyStats.UniqueContacts > 0 {
372→			fmt.Fprintf(&b, " → %d contacts", s.weeklyStats.UniqueContacts)
373→		}
374→		kpiTarget := s.settings["kpi.daily_emails"]
375→		if kpiTarget != "" {
376→			fmt.Fprintf(&b, " (target: %s/day)", kpiTarget)
377→		}
378→		b.WriteString("\n")
379→	} else {
380→		goal := s.settings["kpi.goal"]
381→		if goal != "" {
382→			fmt.Fprintf(&b, "  Goal: %s — no emails sent this week yet\n", goal)
383→		}
384→	}
385→
386→	// Rotate one additional insight based on day-of-year
387→	// This keeps the banner fresh without overwhelming
388→	slot := time.Now().YearDay() % 5
389→	switch slot {
390→	case 0: // Sending health
391→		warmup := s.settings["sending.warmup_status"]
392→		domainType := s.settings["sending.domain_type"]
393→		if warmup == "fresh" {
394→			b.WriteString("  Domain is fresh — warmup in progress, conservative limits active\n")
395→		} else if domainType == "primary" {
396→			b.WriteString("  Sending from primary domain — consider a dedicated outbound domain\n")
397→		} else {
398→			fmt.Fprintf(&b, "  %s emails synced | %d skills active\n", formatCount(s.emailTotal), s.skillCount)
399→		}
400→	case 1: // Data snapshot
401→		fmt.Fprintf(&b, "  Data: %s emails", formatCount(s.emailTotal))
402→		if s.outboundTotal > 0 {
403→			fmt.Fprintf(&b, " (%d outbound)", s.outboundTotal)
404→		}
405→		if s.contactCount > 0 {
406→			fmt.Fprintf(&b, " | %d contacts", s.contactCount)
407→		}
408→		b.WriteString("\n")
409→	case 2: // Learnings
410→		if s.learningCount > 0 {
411→			fmt.Fprintf(&b, "  %d learnings captured — skills improving with every session\n", s.learningCount)
412→		} else {
413→			fmt.Fprintf(&b, "  %d skills active | Start sending to build learnings\n", s.skillCount)
414→		}
415→	case 3: // Connected services
416→		var connList []string
417→		for id, c := range s.connectors {
418→			if c.Connected {
419→				connList = append(connList, capitalize(id))
420→			}
421→		}
422→		fmt.Fprintf(&b, "  Connected: %s | %d skills active\n", strings.Join(connList, ", "), s.skillCount)
423→	case 4: // Quick action suggestion
424→		actions := []string{
425→			"\"research [company]\" — deep-dive a prospect",
426→			"\"write an email to [persona] at [company]\"",
427→			"\"/nurge:review\" — check your KPI progress",
428→			"\"show my pipeline\" — see what needs attention",
429→		}
430→		pick := time.Now().YearDay() / 5 % len(actions)
431→		fmt.Fprintf(&b, "  Try: %s\n", actions[pick])
432→	}
433→
434→	return b.String()
435→}
