437→func buildPromptContext(s *sessionStatus) string {
438→	var b strings.Builder
439→
440→	if !s.configLoaded || !s.setupCompleted {
441→		b.WriteString("You are in a Nurge workspace. Setup is not complete. ")
442→		b.WriteString("Guide the user to run /nurge:setup to finish configuration. ")
443→		b.WriteString("Do not attempt to use nurge data commands — they will have no data yet.")
444→		return b.String()
445→	}
446→
447→	// User context
448→	name := s.settings["user.name"]
449→	role := s.settings["user.role"]
450→	if name != "" {
451→		fmt.Fprintf(&b, "User: %s", name)
452→		if role != "" {
453→			fmt.Fprintf(&b, " (%s)", role)
454→		}
455→		b.WriteString("\n")
456→	}
457→
458→	b.WriteString("You are in a Nurge outbound sales workspace.\n")
459→	fmt.Fprintf(&b, "Status: Setup complete. %s emails synced (%d outbound). %d contacts. %d skills active.\n",
460→		formatCount(s.emailTotal), s.outboundTotal, s.contactCount, s.skillCount)
461→
462→	if syncContext := buildSyncPromptContext(s.startSync); syncContext != "" {
463→		b.WriteString(syncContext)
464→	}
465→	if strategicContext := buildStrategicMemoryPromptContext(s.recentStrategicMemory, s.staleSkills); strategicContext != "" {
466→		b.WriteString(strategicContext)
467→	}
468→
469→	// KPI context
470→	goal := s.settings["kpi.goal"]
471→	dailyTarget := s.settings["kpi.daily_emails"]
472→	weeklyMeetings := s.settings["kpi.weekly_meetings"]
473→	if goal != "" {
474→		fmt.Fprintf(&b, "Outbound goal: %s.", goal)
475→		if dailyTarget != "" {
476→			fmt.Fprintf(&b, " Daily target: %s emails.", dailyTarget)
477→		}
478→		if weeklyMeetings != "" {
479→			fmt.Fprintf(&b, " Weekly meeting target: %s.", weeklyMeetings)
480→		}
481→		b.WriteString("\n")
482→	}
483→
484→	// Sending context
485→	warmup := s.settings["sending.warmup_status"]
486→	domainType := s.settings["sending.domain_type"]
487→	if warmup == "fresh" {
488→		b.WriteString("IMPORTANT: Domain is fresh/not warmed up. Enforce conservative sending limits. Do not exceed daily target.\n")
489→	}
490→	if domainType == "primary" {
491→		b.WriteString("Note: User is sending from primary business domain. Be conservative with volume.\n")
492→	}
493→
494→	// Geography / compliance
495→	geo := s.settings["prospects.geography"]
496→	if geo != "" {
497→		fmt.Fprintf(&b, "Prospect geography: %s.", geo)
498→		if strings.Contains(strings.ToLower(geo), "eu") || strings.Contains(strings.ToLower(geo), "europe") {
499→			b.WriteString(" GDPR applies — ensure legitimate interest basis for outreach.")
500→		}
501→		b.WriteString("\n")
502→	}
503→
504→	// Rules
505→	b.WriteString("Rules:\n")
506→	b.WriteString("- Use `nurge` CLI commands for all data access. Never read .nurge/ directly.\n")
