612→func buildSyncBannerLine(report *sessionSyncReport) string {
613→	if report == nil || !report.Attempted {
614→		return ""
615→	}
616→	if report.Error != "" {
617→		return "Remote sync unavailable — using last local state"
618→	}
619→	if report.RowsUpserted == 0 {
620→		return ""
621→	}
622→
623→	parts := []string{}
624→	if report.Delta != nil {
625→		if report.Delta.TasksSent > 0 {
626→			parts = append(parts, fmt.Sprintf("%d follow-up%s sent", report.Delta.TasksSent, pluralSuffix(report.Delta.TasksSent)))
627→		}
628→		if report.Delta.RepliesNeedingAttention > 0 {
629→			parts = append(parts, fmt.Sprintf("%d repl%s need attention", report.Delta.RepliesNeedingAttention, pluralSuffix(report.Delta.RepliesNeedingAttention, "y", "ies")))
630→		}
631→		if report.Delta.TasksFailed > 0 {
632→			parts = append(parts, fmt.Sprintf("%d send failure%s", report.Delta.TasksFailed, pluralSuffix(report.Delta.TasksFailed)))
633→		}
634→		if len(report.Delta.AuthExpiredMailboxes) > 0 {
635→			parts = append(parts, fmt.Sprintf("%d mailbox reconnect%s needed", len(report.Delta.AuthExpiredMailboxes), pluralSuffix(len(report.Delta.AuthExpiredMailboxes))))
636→		}
637→	}
638→	if len(parts) == 0 {
639→		return fmt.Sprintf("Synced %d remote update%s", report.RowsUpserted, pluralSuffix(report.RowsUpserted))
640→	}
641→	return "While you were away: " + strings.Join(parts, " | ")
642→}
